SELECT COUNT(*) FROM user 
WHERE role = #{role} 
AND is_deleted = 0

SELECT u.id, u.username, u.nickname, u.email, u.phone, u.role, u.department_id as departmentId, COALESCE(d.name, '未分配') as departmentName, u.status, u.remark, u.created_at as createdAt, u.updated_at as updatedAt FROM user u LEFT JOIN department d ON u.department_id = d.id AND d.is_deleted = 0 WHERE u.is_deleted = 0
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%'))
AND u.phone LIKE CONCAT('%', #{phone}, '%')
AND u.role = #{role}
AND u.status = #{status}
AND u.department_id = #{departmentId}
ORDER BY u.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) 
FROM user u
WHERE u.is_deleted = 0

    AND (u.username LIKE CONCAT('%', #{keyword}, '%') 
         OR u.nickname LIKE CONCAT('%', #{keyword}, '%')
         OR u.email LIKE CONCAT('%', #{keyword}, '%'))


    AND u.phone LIKE CONCAT('%', #{phone}, '%')


    AND u.role = #{role}


    AND u.status = #{status}


    AND u.department_id = #{departmentId}
